import urllib.request
import urllib.parse
import json

BASE_URL = "http://the-agent-company.com:8929"
PROJECT = "root%2Fsotopia"
ISSUE_IID = 200

# Try different tokens
tokens = ["root", ""]

def get_issue(token):
    url = f"{BASE_URL}/api/v4/projects/{PROJECT}/issues/{ISSUE_IID}"
    req = urllib.request.Request(url)
    if token:
        req.add_header("PRIVATE-TOKEN", token)
    try:
        with urllib.request.urlopen(req, timeout=10) as resp:
            return json.loads(resp.read())
    except Exception as e:
        return {"error": str(e)}

for token in tokens:
    result = get_issue(token)
    print(f"Token '{token}': {json.dumps(result, indent=2)[:500]}")
    if "error" not in result:
        break
